                {"swissGerman": "vorstrecke", "german": "vorstrecken", "explanation": "'vorstrecke' = 'vorstrecken'. To advance payment."},
                {"swissGerman": "bechume", "german": "bekomme", "explanation": "'bechume' = 'bekomme'. K→Ch shift."},
